module.render:
const color = args.color || 'var(--accent-color)';
const current = parseInt(args.current, 10) || 0;
const numbered = String(args.numbered) !== 'false';
let html = `\n\n<div class="mdp-mod-agenda${current ? ' has-current' : ''}" style="--ag-color:${color};">`;
let i = 0;
sections.forEach((s) => {
  const c = (s || '').trim();
  if (!c) return;
  i += 1;
  const on = i === current;
  html += `<div class="mdp-ag-item${on ? ' is-current' : ''}">` +
    (numbered ? `<span class="mdp-ag-num">${i}</span>` : '') +
    `<div class="mdp-ag-text">\n\n${c}\n\n</div></div>`;
});
html += `</div>\n\n`;
return html;
